1	/**
2	 * LayerInfinite MCP Server — types.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Shared domain types for the V2 Gateway Proxy.
5	 * Imports config types from config.ts; defines gateway-specific types here.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	import type { LIMode } from './config.js';
10	
11	/** Gateway operating mode (bootstrap = mode null, observe only). */
12	export type GatewayMode = 'bootstrap' | LIMode;
13	
14	/** Enriched tool returned by tools/list interception. */
15	export interface EnrichedTool {
16	  name: string;
17	  /** ENRICHED description — original woven with historical context. Never modify inputSchema. */
18	  description: string;
19	  /** UNMODIFIED — passthrough from upstream. */
20	  inputSchema: Record<string, unknown>;
21	  /** Which upstream server owns this tool. */
22	  upstreamName: string;
23	  annotations?: {
24	    /** 1-based rank within task (best=1). */
25	    ranking?: number;
26	    category?: 'recommended' | 'neutral' | 'warning';
27	  };
28	}
29	
30	/** Context gathered before enriching tool descriptions. */
31	export interface EnrichmentContext {
32	  taskType: string;
33	  customerId: string;
34	  agentId: string;
35	  mode: GatewayMode;
36	  scores: ScoredAction[];
37	  policyDecision: PolicyDecision | null;
38	}
39	
40	/** A scored action from the LI scoring engine. */
41	export interface ScoredAction {
42	  actionName: string;
43	  compositeScore: number;
44	  successRate: number;
45	  sampleSize: number;
46	  trendLabel?: string;
47	}
48	
49	/** Policy decision from the LI policy engine. */
50	export interface PolicyDecision {
51	  action: string;
52	  reason: string;
53	  confidence: number;
54	}
55	
56	/** A decision record — one tool invocation tracked by the gateway. */
57	export interface DecisionRecord {
58	  /** Format: dec_{ts12}_{agent4}_{rand4} — lexicographically sortable. */
59	  decisionId: string;
60	  agentId: string;
61	  customerId: string;
62	  taskType: string;
63	  actionName: string;
64	  upstreamName: string;
65	  /** What the agent chose. */
66	  originalAction: string;
67	  /** What actually ran (may differ in Auto mode). */
68	  executedAction: string;
69	  mode: GatewayMode;
70	  rerouted: boolean;
71	  enrichmentScores: Record<string, number>;
72	  /** ISO 8601 timestamp. */
73	  timestamp: string;
74	}
75	
76	/** An episode — a session containing multiple decisions. */
77	export interface Episode {
78	  episodeId: string;
79	  agentId: string;
80	  sessionStart: string;
81	  /** Ordered list of decisionIds. */
82	  decisions: string[];
83	  /** Max 3 coachings per episode. */
84	  coachingCount: number;
85	}
86	
87	/** Webhook callback from Layer 2 (session) or Layer 3 (business). */
88	export interface WebhookCallback {
89	  decisionId: string;
90	  /** 2 = session outcome, 3 = business outcome. */
91	  layer: 2 | 3;
92	  success: boolean;
93	  reason?: string;
94	  metadata?: Record<string, unknown>;
95	  timestamp: string;
96	}
97	
98	/** In-memory fail-open state for circuit breaker + health tracking. */
99	export interface FailOpenState {
100	  upstreamFailures: Map<string, number>;
101	  circuitBreakerOpen: Map<string, boolean>;
102	  lastHealthCheck: Map<string, number>;
103	  totalRequests: number;
104	  passthroughRequests: number;
105	}
106	
107	/** Outcome payload sent to LI API for logging. */
108	export interface OutcomePayload {
109	  decision_id: string;
110	  agent_id: string;
111	  customer_id: string;
112	  task_type: string;
113	  action_name: string;
114	  upstream_name: string;
115	  original_action: string;
116	  executed_action: string;
117	  mode: string;
118	  rerouted: boolean;
119	  success?: boolean;
120	  latency_ms: number;
121	  timestamp: string;
122	  ingestion_source: 'mcp';
123	  environment: string;
124	}
125

1	/**
2	 * LayerInfinite MCP Server — config.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * V2 Gateway Configuration. Supports upstream MCP servers,
5	 * per-task-type mode overrides, shadow mode, and environment isolation.
6	 *
7	 * Backwards-compatible: all V1 env vars (LAYERINFINITE_API_KEY,
8	 * LAYERINFINITE_BASE_URL, LAYERINFINITE_MODE, LAYERINFINITE_ADMIN_KEY)
9	 * continue to work.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	export type LIMode = 'recommend' | 'assist' | 'auto';
14	
15	export interface UpstreamServer {
16	  /** Human-readable name. Used as tool prefix (e.g. "github" → "github_push_fix"). */
17	  readonly name: string;
18	  /** MCP server URL (e.g., "https://github-mcp.example.com"). */
19	  readonly url: string;
20	  /** Optional per-upstream API key. Falls back to LAYERINFINITE_API_KEY if unset. */
21	  readonly apiKey?: string;
22	  /** Health check interval in ms. Default 30_000. */
23	  readonly healthCheckIntervalMs?: number;
24	}
25	
26	export interface GatewayConfig {
27	  /** API key for authenticating with the LayerInfinite REST API. */
28	  readonly apiKey: string;
29	  /** Base URL of the LayerInfinite API (no trailing slash). */
30	  readonly baseUrl: string;
31	  /** Global operating mode. null = bootstrap (observe only). */
32	  readonly mode: LIMode | null;
33	  /** Upstream MCP servers to proxy. */
34	  readonly upstreamServers: readonly UpstreamServer[];
35	  /** Per-task-type mode overrides. Key = task_type, value = mode. */
36	  readonly modeOverrides: ReadonlyMap<string, LIMode>;
37	  /** If true, LI observes and logs but does NOT inject enrichment. */
38	  readonly shadowMode: boolean;
39	  /** Deployment environment. Staging outcomes are isolated from production. */
40	  readonly environment: 'staging' | 'production';
41	  /** Admin key for gated operations. null = admin disabled. */
42	  readonly adminKey: string | null;
43	  /** Log level. Default derived from NODE_ENV. */
44	  readonly logLevel: 'debug' | 'info' | 'warn' | 'error';
45	}
46	
47	const VALID_MODES: ReadonlySet<string> = new Set(['recommend', 'assist', 'auto']);
48	const VALID_ENVIRONMENTS: ReadonlySet<string> = new Set(['staging', 'production']);
49	
50	function parseUpstreamServers(raw: string): UpstreamServer[] {
51	  try {
52	    const parsed = JSON.parse(raw);
53	    if (!Array.isArray(parsed)) {
54	      throw new Error('LAYERINFINITE_UPSTREAM_TOOLS must be a JSON array');
55	    }
56	    return parsed.map((item: Record<string, unknown>, i: number) => {
57	      if (typeof item.name !== 'string' || item.name.trim() === '') {
58	        throw new Error(`Upstream server at index ${i}: "name" is required and must be a non-empty string`);
59	      }
60	      if (typeof item.url !== 'string' || item.url.trim() === '') {
61	        throw new Error(`Upstream server "${item.name}": "url" is required and must be a non-empty string`);
62	      }
63	      return {
64	        name: item.name.trim(),
65	        url: item.url.trim(),
66	        apiKey: typeof item.apiKey === 'string' ? item.apiKey : undefined,
67	        healthCheckIntervalMs: typeof item.healthCheckIntervalMs === 'number' ? item.healthCheckIntervalMs : undefined,
68	      };
69	    });
70	  } catch (err) {
71	    if (err instanceof SyntaxError) {
72	      throw new Error(`LAYERINFINITE_UPSTREAM_TOOLS is not valid JSON: ${err.message}`);
73	    }
74	    throw err;
75	  }
76	}
77	
78	function parseModeOverrides(raw: string): Map<string, LIMode> {
79	  if (!raw || raw.trim() === '' || raw.trim() === '{}') {
80	    return new Map();
81	  }
82	  try {
83	    const parsed = JSON.parse(raw);
84	    if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
85	      throw new Error('LAYERINFINITE_MODE_OVERRIDES must be a JSON object (e.g., {"build_failed":"auto"})');
86	    }
87	    const map = new Map<string, LIMode>();
88	    for (const [taskType, mode] of Object.entries(parsed)) {
89	      if (typeof mode !== 'string' || !VALID_MODES.has(mode)) {
90	        throw new Error(
91	          `LAYERINFINITE_MODE_OVERRIDES: invalid mode "${String(mode)}" for task "${taskType}". ` +
92	          `Valid values: recommend, assist, auto.`,
93	        );
94	      }
95	      map.set(taskType, mode as LIMode);
96	    }
97	    return map;
98	  } catch (err) {
99	    if (err instanceof SyntaxError) {
100	      throw new Error(`LAYERINFINITE_MODE_OVERRIDES is not valid JSON: ${err.message}`);
101	    }
102	    throw err;
103	  }
104	}
105	
106	/**
107	 * Reads and validates environment variables.
108	 * Throws immediately if required vars are missing — fail fast at startup.
109	 */
110	export function loadConfig(): GatewayConfig {
111	  // ── V1 backwards-compatible vars ──────────────────────────
112	  const apiKey = process.env.LAYERINFINITE_API_KEY;
113	  if (!apiKey || apiKey.trim() === '') {
114	    throw new Error(
115	      '[layerinfinite-mcp] LAYERINFINITE_API_KEY is required. ' +
116	      'Get your key from the LayerInfinite dashboard.',
117	    );
118	  }
119	
120	  const baseUrl = (process.env.LAYERINFINITE_BASE_URL ?? 'https://layerinfinite.me').replace(/\/+$/, '');
121	
122	  const rawMode = (process.env.LAYERINFINITE_MODE ?? '').trim().toLowerCase();
123	  let mode: LIMode | null = null;
124	  if (rawMode !== '') {
125	    if (!VALID_MODES.has(rawMode)) {
126	      throw new Error(
127	        `[layerinfinite-mcp] Invalid LAYERINFINITE_MODE="${rawMode}". ` +
128	        `Valid values: recommend, assist, auto. Omit for bootstrap mode.`,
129	      );
130	    }
131	    mode = rawMode as LIMode;
132	  }
133	
134	  const adminKey = process.env.LAYERINFINITE_ADMIN_KEY?.trim() || null;
135	
136	  // ── V2 new vars ──────────────────────────────────────────
137	  const rawUpstream = (process.env.LAYERINFINITE_UPSTREAM_TOOLS ?? '[]').trim();
138	  const upstreamServers = parseUpstreamServers(rawUpstream);
139	
140	  const rawOverrides = (process.env.LAYERINFINITE_MODE_OVERRIDES ?? '{}').trim();
141	  const modeOverrides = parseModeOverrides(rawOverrides);
142	
143	  const shadowMode = (process.env.LAYERINFINITE_SHADOW_MODE ?? 'false').trim().toLowerCase() === 'true';
144	
145	  const rawEnv = (process.env.LAYERINFINITE_ENVIRONMENT ?? 'production').trim().toLowerCase();
146	  if (!VALID_ENVIRONMENTS.has(rawEnv)) {
147	    throw new Error(
148	      `[layerinfinite-mcp] Invalid LAYERINFINITE_ENVIRONMENT="${rawEnv}". ` +
149	      `Valid values: staging, production.`,
150	    );
151	  }
152	  const environment = rawEnv as 'staging' | 'production';
153	
154	  const logLevel = resolveLogLevel();
155	
156	  const config: GatewayConfig = Object.freeze({
157	    apiKey,
158	    baseUrl,
159	    mode,
160	    upstreamServers,
161	    modeOverrides,
162	    shadowMode,
163	    environment,
164	    adminKey,
165	    logLevel,
166	  });
167	
168	  return config;
169	}
170	
171	function resolveLogLevel(): GatewayConfig['logLevel'] {
172	  const raw = (process.env.LAYERINFINITE_LOG_LEVEL ?? '').trim().toLowerCase();
173	  if (['debug', 'info', 'warn', 'error'].includes(raw)) {
174	    return raw as GatewayConfig['logLevel'];
175	  }
176	  // Derive from NODE_ENV
177	  if (process.env.NODE_ENV === 'production') return 'info';
178	  if (process.env.NODE_ENV === 'test') return 'error';
179	  return 'debug';
180	}
