35	
36	/** Handle a call to the virtual li_recommend tool. */
37	export async function handleLiRecommend(
38	  liApi: LiApiClient,
39	  taskType: string,
40	  customerId: string,
41	  agentId: string,
42	): Promise<UpstreamCallResult> {
43	  try {
44	    const scores = await liApi.getScores(taskType, customerId, agentId);
45	    const text = formatRecommendations(scores);
46	    return { content: [{ type: 'text', text }] };
47	  } catch (err) {
48	    log.warn('li_recommend failed', {
49	      error: err instanceof Error ? err.message : String(err),
50	    });
51	    return {
52	      content: [
53	        {
54	          type: 'text',
55	          text: 'Unable to fetch recommendations right now. Please try again or select a tool manually.',
56	        },
57	      ],
58	      isError: true,
59	    };
60	  }
61	}
62	
63	function formatRecommendations(scores: ScoredAction[]): string {
64	  if (scores.length === 0) {
65	    return 'No recommendations available yet. Execute a few tasks to build up outcome history.';
66	  }
67	
68	  const ranked = [...scores]
69	    .sort((a, b) => b.compositeScore - a.compositeScore)
70	    .slice(0, 5);
71	
72	  const lines = ['**Top recommended tools:**', ''];
73	
74	  for (let i = 0; i < ranked.length; i++) {
75	    const s = ranked[i];
76	    const icon = trendIcon(s.trendLabel);
77	    const warning = s.successRate < 50 && s.sampleSize >= 5 ? ' ⚠ BELOW THRESHOLD' : '';
78	    lines.push(
79	      `${i + 1}. **${s.actionName}** — ${s.successRate}% success (${s.sampleSize} runs)${icon}${warning}`,
80	    );
81	  }
82	
83	  lines.push('');
84	  lines.push(
85	    ranked.length > 1
86	      ? 'Call a tool by name to execute it. LayerInfinite will automatically reroute in Auto mode when a better tool is available.'
87	      : 'This is the only tool with outcome history for this task type.',
88	  );
89	
90	  return lines.join('\n');
91	}
92	
93	function trendIcon(trendLabel?: string): string {
94	  if (!trendLabel) return '';
95	  switch (trendLabel) {
96	    case 'strongly_improving':
97	    case 'improving':
98	      return ' ↑';
99	    case 'declining':
100	    case 'sharply_declining':
101	      return ' ↓';
102	    default:
103	      return '';
104	  }
105	}
