1	/**
2	 * LayerInfinite API — webhook-verifier.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Business webhook verification: HMAC-SHA256 signatures,
5	 * timestamp validation, per-customer secrets, rate limiting.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	import crypto from 'node:crypto';
10	import { supabase } from './supabase.js';
11	
12	// ── Constants ────────────────────────────────────────────────
13	
14	const MAX_TIMESTAMP_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours
15	const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
16	const RATE_LIMIT_MAX_PER_WINDOW = 100; // 100 requests per minute per customer
17	
18	// ── In-memory rate limiter ───────────────────────────────────
19	
20	interface RateLimitBucket {
21	  count: number;
22	  windowStart: number;
23	}
24	
25	const rateLimitBuckets = new Map<string, RateLimitBucket>();
26	
27	// Periodic cleanup of stale buckets (every 5 minutes)
28	setInterval(() => {
29	  const cutoff = Date.now() - RATE_LIMIT_WINDOW_MS;
30	  for (const [key, bucket] of rateLimitBuckets) {
31	    if (bucket.windowStart < cutoff) {
32	      rateLimitBuckets.delete(key);
33	    }
34	  }
35	}, 5 * 60 * 1000).unref();
36	
37	// ── Public API ───────────────────────────────────────────────
38	
39	/**
40	 * Verify HMAC-SHA256 signature on a webhook request body.
41	 *
42	 * The client signs the raw body with their per-customer webhook secret
43	 * and sends the signature in the X-LI-Webhook-Signature header.
44	 * Format: t={unix_timestamp},v1={hex_hmac_sha256}
45	 */
46	export async function verifyBusinessWebhook(
47	  rawBody: string,
48	  signatureHeader: string | undefined,
49	  customerId: string,
50	): Promise<boolean> {
51	  if (!signatureHeader || !customerId) return false;
52	
53	  // Parse signature header: t={ts},v1={sig}
54	  let timestamp: number | null = null;
55	  const v1Candidates: string[] = [];
56	
57	  for (const part of signatureHeader.split(',')) {
58	    const [key, value] = part.trim().split('=', 2);
59	    if (!key || !value) continue;
60	
61	    if (key === 't') {
62	      const parsed = Number(value);
63	      timestamp = Number.isFinite(parsed) ? parsed : null;
64	    }
65	    if (key === 'v1') {
66	      v1Candidates.push(value.toLowerCase());
67	    }
68	  }
69	
70	  if (timestamp === null || v1Candidates.length === 0) return false;
71	
72	  // Validate timestamp
73	  if (!isTimestampValid(timestamp)) return false;
74	
75	  // Fetch customer's webhook secret
76	  const secret = await getCustomerWebhookSecret(customerId);
77	  if (!secret) return false;
78	
79	  // Compute expected signature
80	  const signedPayload = `${timestamp}.${rawBody}`;
81	  const expectedSignature = crypto
82	    .createHmac('sha256', secret)
83	    .update(signedPayload)
84	    .digest('hex')
85	    .toLowerCase();
86	
87	  // Constant-time comparison against all v1 candidates
88	  for (const candidate of v1Candidates) {
89	    if (timingSafeEqual(expectedSignature, candidate)) {
90	      return true;
91	    }
92	  }
93	
94	  return false;
95	}
96	
97	/**
98	 * Validate that a webhook timestamp is not too old (>24h) or in the future.
99	 */
100	export function isTimestampValid(unixSeconds: number, maxAgeMs = MAX_TIMESTAMP_AGE_MS): boolean {
101	  const nowMs = Date.now();
102	  const tsMs = unixSeconds * 1000;
103	
104	  // Reject future timestamps (with 30s clock skew tolerance)
105	  if (tsMs > nowMs + 30_000) return false;
106	
107	  // Reject timestamps older than maxAgeMs
108	  if (nowMs - tsMs > maxAgeMs) return false;
109	
110	  return true;
111	}
112	
113	/**
114	 * Check rate limit for a customer. Returns true if allowed, false if exceeded.
115	 * 100 requests per minute per customer (sliding window).
116	 */
117	export function checkRateLimit(customerId: string): boolean {
118	  const now = Date.now();
119	  const key = `customer:${customerId}`;
120	  const bucket = rateLimitBuckets.get(key);
121	
122	  if (!bucket || now - bucket.windowStart >= RATE_LIMIT_WINDOW_MS) {
123	    // New window
124	    rateLimitBuckets.set(key, { count: 1, windowStart: now });
125	    return true;
126	  }
127	
128	  if (bucket.count >= RATE_LIMIT_MAX_PER_WINDOW) {
129	    return false;
130	  }
131	
132	  bucket.count++;
133	  return true;
134	}
135	
136	// ── Private ──────────────────────────────────────────────────
137	
138	/**
139	 * Fetch the customer's webhook secret from dim_customers.config.webhook_secret.
140	 * Returns null if no secret is configured.
141	 */
142	async function getCustomerWebhookSecret(customerId: string): Promise<string | null> {
143	  try {
144	    const { data, error } = await supabase
145	      .from('dim_customers')
146	      .select('config')
147	      .eq('customer_id', customerId)
148	      .maybeSingle();
149	
150	    if (error || !data?.config) return null;
151	
152	    const config = data.config as Record<string, unknown>;
153	    const secret = config.webhook_secret;
154	
155	    if (typeof secret !== 'string' || secret.length < 16) return null;
156	
157	    return secret;
158	  } catch {
159	    // DB access failure — reject verification (secure by default)
160	    return null;
161	  }
162	}
163	
164	/**
165	 * Constant-time string comparison to prevent timing attacks.
166	 */
167	function timingSafeEqual(a: string, b: string): boolean {
168	  const bufA = Buffer.from(a);
169	  const bufB = Buffer.from(b);
170	
171	  if (bufA.length !== bufB.length) return false;
172	
173	  return crypto.timingSafeEqual(bufA, bufB);
174	}
