1	/**
2	 * LayerInfinite API — lib/shadow-mode.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Shadow mode: observe + compare agent tool choices against LI
5	 * enrichment recommendations without injecting enrichment into
6	 * the live tool list. Records divergence for offline analysis.
7	 *
8	 * Gating: enabled per-agent via dim_agents.config.shadow_mode
9	 *   { enabled: true, sample_rate: 0.1 }
10	 *
11	 * Records to shadow_observations table:
12	 *   - What LI would have recommended (top N actions)
13	 *   - What the agent actually chose
14	 *   - Whether the agent followed the recommendation
15	 * ══════════════════════════════════════════════════════════════
16	 */
17	
18	import { supabase } from './supabase.js';
19	
20	// ── Types ──────────────────────────────────────────────────────
21	
22	export interface ShadowObservation {
23	  agent_id: string;
24	  customer_id: string;
25	  context_id: string;
26	  task_type: string;
27	  /** Top-ranked actions LI would have recommended. */
28	  recommended_actions: Array<{
29	    action_name: string;
30	    composite_score: number;
31	    rank: number;
32	  }>;
33	  /** The action the agent actually chose. */
34	  chosen_action: string;
35	  /** Whether the agent picked the top recommendation. */
36	  followed_recommendation: boolean;
37	  /** Rank of the chosen action in recommendations (-1 if not in list). */
38	  chosen_rank: number;
39	  /** Score delta: top_recommended_score - chosen_score (positive = agent picked worse). */
40	  score_delta: number;
41	  environment: string;
42	  timestamp: string;
43	}
44	
45	export interface ShadowConfig {
46	  enabled: boolean;
47	  /** Fraction of requests to shadow (0.0–1.0). */
48	  sample_rate: number;
49	}
50	
51	interface ShadowCacheEntry {
52	  config: ShadowConfig;
53	  expiresAt: number;
54	}
55	
56	// ── Cache ──────────────────────────────────────────────────────
57	
58	const configCache = new Map<string, ShadowCacheEntry>();
59	const CONFIG_TTL_MS = 5 * 60 * 1000;
60	
61	// ── Public API ─────────────────────────────────────────────────
62	
63	/**
64	 * Check if shadow mode is enabled for a given agent.
65	 * Returns the shadow config (including sample_rate) or null.
66	 */
67	export async function getShadowConfig(
68	  agentId: string,
69	  customerId: string,
70	): Promise<ShadowConfig | null> {
71	  const cacheKey = `${customerId}:${agentId}`;
72	  const cached = configCache.get(cacheKey);
73	  if (cached && cached.expiresAt > Date.now()) {
74	    return cached.config;
75	  }
76	
77	  try {
78	    const { data, error } = await supabase
79	      .from('dim_agents')
80	      .select('config')
81	      .eq('agent_id', agentId)
82	      .eq('customer_id', customerId)
83	      .maybeSingle();
84	
85	    if (error || !data?.config) {
86	      configCache.set(cacheKey, {
87	        config: { enabled: false, sample_rate: 0 },
88	        expiresAt: Date.now() + CONFIG_TTL_MS,
89	      });
90	      return null;
91	    }
92	
93	    const config = data.config as Record<string, unknown>;
94	    const shadow = config.shadow_mode as ShadowConfig | undefined;
95	
96	    if (!shadow?.enabled) {
97	      configCache.set(cacheKey, {
98	        config: { enabled: false, sample_rate: 0 },
99	        expiresAt: Date.now() + CONFIG_TTL_MS,
100	      });
101	      return null;
102	    }
103	
104	    const resolved: ShadowConfig = {
105	      enabled: true,
106	      sample_rate: typeof shadow.sample_rate === 'number' ? shadow.sample_rate : 0.1,
107	    };
108	
109	    configCache.set(cacheKey, {
110	      config: resolved,
111	      expiresAt: Date.now() + CONFIG_TTL_MS,
112	    });
113	
114	    return resolved;
115	  } catch {
116	    return null;
117	  }
118	}
119	
120	/**
121	 * Decide whether to shadow this specific request.
122	 * Returns true at `sample_rate` frequency, respecting per-agent config.
123	 */
124	export function shouldShadow(config: ShadowConfig): boolean {
125	  if (!config.enabled || config.sample_rate <= 0) return false;
126	  if (config.sample_rate >= 1) return true;
127	  return Math.random() < config.sample_rate;
128	}
129	
130	/**
131	 * Record a shadow observation — what LI recommended vs. what the agent chose.
132	 * Fire-and-forget: failures are logged but never thrown to the caller.
133	 */
134	export async function recordShadowObservation(
135	  observation: Omit<ShadowObservation, 'followed_recommendation' | 'chosen_rank' | 'score_delta'> & {
136	    followed_recommendation?: boolean;
137	    chosen_rank?: number;
138	    score_delta?: number;
139	  },
140	): Promise<void> {
141	  const topScore = observation.recommended_actions[0]?.composite_score ?? 0;
142	  const chosenEntry = observation.recommended_actions.find(
143	    (a) => a.action_name === observation.chosen_action,
144	  );
145	  const chosenRank = chosenEntry ? chosenEntry.rank : -1;
146	  const chosenScore = chosenEntry?.composite_score ?? 0;
147	  const followed = chosenRank === 1;
148	
149	  const record: ShadowObservation = {
150	    ...observation,
151	    followed_recommendation: observation.followed_recommendation ?? followed,
152	    chosen_rank: observation.chosen_rank ?? chosenRank,
153	    score_delta: observation.score_delta ?? (topScore - chosenScore),
154	  };
155	
156	  try {
157	    const { error } = await supabase
158	      .from('shadow_observations')
159	      .insert({
160	        agent_id: record.agent_id,
161	        customer_id: record.customer_id,
162	        context_id: record.context_id,
163	        task_type: record.task_type,
164	        recommended_actions: record.recommended_actions,
165	        chosen_action: record.chosen_action,
166	        followed_recommendation: record.followed_recommendation,
167	        chosen_rank: record.chosen_rank,
168	        score_delta: record.score_delta,
169	        environment: record.environment,
170	        timestamp: record.timestamp,
171	      });
172	
173	    if (error) {
174	      console.warn('[shadow-mode] Failed to record observation:', error.message);
175	    }
176	  } catch (err: any) {
177	    console.warn('[shadow-mode] Record failed:', err.message);
178	  }
179	}
180	
181	/**
182	 * Compute shadow stats for a time window.
183	 * Returns follow rate and average score delta.
184	 */
185	export async function getShadowStats(
186	  customerId: string,
187	  agentId: string,
188	  sinceHours = 24,
189	): Promise<{
190	  total_observations: number;
191	  follow_rate: number;
192	  avg_score_delta: number;
193	  avg_chosen_rank: number;
194	}> {
195	  const since = new Date(Date.now() - sinceHours * 3_600_000).toISOString();
196	
197	  try {
198	    const { data, error } = await supabase
199	      .from('shadow_observations')
200	      .select('followed_recommendation, score_delta, chosen_rank')
201	      .eq('customer_id', customerId)
202	      .eq('agent_id', agentId)
203	      .gte('timestamp', since);
204	
205	    if (error || !data || data.length === 0) {
206	      return { total_observations: 0, follow_rate: 0, avg_score_delta: 0, avg_chosen_rank: 0 };
207	    }
208	
209	    const rows = data as Array<{
210	      followed_recommendation: boolean;
211	      score_delta: number;
212	      chosen_rank: number;
213	    }>;
214	
215	    const total = rows.length;
216	    const follows = rows.filter((r) => r.followed_recommendation).length;
217	    const avgDelta = rows.reduce((s, r) => s + (r.score_delta ?? 0), 0) / total;
218	    const avgRank = rows.reduce((s, r) => s + (r.chosen_rank ?? 0), 0) / total;
219	
220	    return {
221	      total_observations: total,
222	      follow_rate: Math.round((follows / total) * 10000) / 10000,
223	      avg_score_delta: Math.round(avgDelta * 10000) / 10000,
224	      avg_chosen_rank: Math.round(avgRank * 100) / 100,
225	    };
226	  } catch {
227	    return { total_observations: 0, follow_rate: 0, avg_score_delta: 0, avg_chosen_rank: 0 };
228	  }
229	}
230	
231	/** Invalidate cached shadow config for an agent. */
232	export function invalidateShadowConfig(agentId: string, customerId: string): void {
233	  configCache.delete(`${customerId}:${agentId}`);
234	}
