1	/**
2	 * LayerInfinite API — lib/environment-isolation.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Environment isolation: ensures staging data never pollutes
5	 * production probability models or materialized views.
6	 *
7	 * Rules:
8	 *   - Outcomes in staging are tagged environment='staging'
9	 *   - Materialized views filter WHERE environment = 'production'
10	 *   - World model training only uses production data
11	 *   - Staging outcomes can be queried separately for testing
12	 *
13	 * Environment detection:
14	 *   1. Explicit X-LI-Environment header (set by MCP gateway)
15	 *   2. NODE_ENV fallback
16	 *   3. Defaults to 'production' when unknown
17	 * ══════════════════════════════════════════════════════════════
18	 */
19	
20	export type Environment = 'production' | 'staging' | 'development';
21	
22	const VALID_ENVIRONMENTS: ReadonlySet<string> = new Set([
23	  'production',
24	  'staging',
25	  'development',
26	]);
27	
28	// ── Public API ─────────────────────────────────────────────────
29	
30	/**
31	 * Resolve the environment for a request.
32	 * Precedence: header > NODE_ENV > default('production').
33	 */
34	export function resolveEnvironment(headerValue?: string | null): Environment {
35	  if (headerValue) {
36	    const normalized = headerValue.toLowerCase().trim();
37	    if (VALID_ENVIRONMENTS.has(normalized)) {
38	      return normalized as Environment;
39	    }
40	  }
41	
42	  const nodeEnv = process.env.NODE_ENV?.toLowerCase().trim();
43	  if (nodeEnv && VALID_ENVIRONMENTS.has(nodeEnv)) {
44	    return nodeEnv as Environment;
45	  }
46	
47	  return 'production';
48	}
49	
50	/**
51	 * Is the given environment a non-production (staging/dev) environment?
52	 */
53	export function isNonProduction(env: Environment): boolean {
54	  return env === 'staging' || env === 'development';
55	}
56	
57	/**
58	 * Is the given environment production?
59	 */
60	export function isProduction(env: Environment): boolean {
61	  return env === 'production';
62	}
63	
64	/**
65	 * Build the environment filter suffix for Supabase queries.
66	 * In production: `.eq('environment', 'production')` (or no filter for
67	 * tables that store only production data).
68	 * In staging: `.eq('environment', 'staging')` for isolation.
69	 *
70	 * Returns the filter value to use in `.eq('environment', value)`.
71	 * Returns null if no filter should be applied (all environments).
72	 */
73	export function getEnvironmentFilter(
74	  env: Environment,
75	  includeStaging = false,
76	): string | null {
77	  if (includeStaging) return null; // no filter — all environments
78	  return env;
79	}
80	
81	/**
82	 * Tag an outcome row with its environment before writing to DB.
83	 * Returns the environment tag to set on the outcome record.
84	 *
85	 * Callers should set:
86	 *   environment = tagOutcomeWithEnvironment(env)
87	 * in their INSERT/UPDATE payloads.
88	 */
89	export function tagOutcomeWithEnvironment(env: Environment): string {
90	  return env;
91	}
92	
93	/**
94	 * Validate that an environment transition is safe.
95	 *
96	 * Staging → Production: OK (promotion)
97	 * Production → Staging: BLOCKED (downgrade)
98	 * Same → Same: OK (no-op)
99	 */
100	export function validateEnvironmentTransition(
101	  from: Environment,
102	  to: Environment,
103	): { allowed: boolean; reason?: string } {
104	  if (from === to) return { allowed: true };
105	
106	  if (from === 'staging' && to === 'production') {
107	    return { allowed: true };
108	  }
109	
110	  if (from === 'production' && to === 'staging') {
111	    return {
112	      allowed: false,
113	      reason: 'Cannot downgrade production data to staging',
114	    };
115	  }
116	
117	  if (from === 'development' && (to === 'staging' || to === 'production')) {
118	    return { allowed: true };
119	  }
120	
121	  return { allowed: true };
122	}
123	
124	/**
125	 * Build a Supabase query filter for environment-aware queries.
126	 *
127	 * Usage:
128	 *   const filter = buildEnvQueryFilter(env);
129	 *   let query = supabase.from('fact_outcomes').select('*');
130	 *   if (filter) query = query.eq('environment', filter);
131	 */
132	export function buildEnvQueryFilter(
133	  env: Environment,
134	  options?: { includeAll?: boolean },
135	): string | null {
136	  if (options?.includeAll) return null;
137	  return env;
138	}
