1	/**
2	 * LayerInfinite API — lib/confidence-thresholds.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Per-agent per-task confidence thresholds loaded from
5	 * dim_agents.config JSONB.
6	 *
7	 * Each agent's config may specify thresholds per task_type:
8	 *   {
9	 *     "confidence_thresholds": {
10	 *       "build_failed": {
11	 *         "minimum_success_rate": 0.6,
12	 *         "minimum_sample_size": 10,
13	 *         "fallback_behavior": "warn"
14	 *       }
15	 *     }
16	 *   }
17	 *
18	 * If no per-task threshold exists, the agent-level default applies.
19	 * If no agent-level default exists, the global defaults apply.
20	 *
21	 * Fallback behaviors:
22	 *   - "omit":    Exclude actions below threshold from enrichment
23	 *   - "warn":    Include but annotate with a warning
24	 *   - "allow":   Include without restriction (bypass thresholds)
25	 * ══════════════════════════════════════════════════════════════
26	 */
27	
28	import { supabase } from './supabase.js';
29	
30	// ── Types ──────────────────────────────────────────────────────
31	
32	export type FallbackBehavior = 'omit' | 'warn' | 'allow';
33	
34	export interface TaskConfidenceThreshold {
35	  minimum_success_rate: number;
36	  minimum_sample_size: number;
37	  fallback_behavior: FallbackBehavior;
38	}
39	
40	export interface AgentConfidenceConfig {
41	  /** Per-task-type overrides. */
42	  thresholds: Map<string, TaskConfidenceThreshold>;
43	  /** Agent-level defaults. */
44	  defaults: TaskConfidenceThreshold;
45	}
46	
47	// ── Global defaults ────────────────────────────────────────────
48	
49	const GLOBAL_DEFAULTS: TaskConfidenceThreshold = {
50	  minimum_success_rate: 0.0,
51	  minimum_sample_size: 1,
52	  fallback_behavior: 'allow',
53	};
54	
55	// ── Cache ──────────────────────────────────────────────────────
56	
57	interface CacheEntry {
58	  config: AgentConfidenceConfig;
59	  expiresAt: number;
60	}
61	
62	const configCache = new Map<string, CacheEntry>();
63	const CONFIG_TTL_MS = 5 * 60 * 1000;
64	
65	function cacheKey(customerId: string, agentId: string): string {
66	  return `${customerId}:${agentId}`;
67	}
68	
69	// ── Public API ─────────────────────────────────────────────────
70	
71	/**
72	 * Load confidence thresholds for an agent.
73	 * Returns a merged config: per-task overrides + agent defaults + global defaults.
74	 */
75	export async function getConfidenceConfig(
76	  customerId: string,
77	  agentId: string,
78	): Promise<AgentConfidenceConfig> {
79	  const key = cacheKey(customerId, agentId);
80	  const cached = configCache.get(key);
81	  if (cached && cached.expiresAt > Date.now()) {
82	    return cached.config;
83	  }
84	
85	  try {
86	    const { data, error } = await supabase
87	      .from('dim_agents')
88	      .select('config')
89	      .eq('agent_id', agentId)
90	      .eq('customer_id', customerId)
91	      .maybeSingle();
92	
93	    const rawConfig = (data?.config as Record<string, unknown>) ?? {};
94	    const ctConfig = rawConfig.confidence_thresholds as Record<string, Record<string, unknown>> | undefined;
95	
96	    // Parse agent-level defaults
97	    const agentDefaults = ctConfig?.['*'] as Record<string, unknown> | undefined;
98	    const defaults: TaskConfidenceThreshold = {
99	      minimum_success_rate: (agentDefaults?.minimum_success_rate as number)
100	        ?? GLOBAL_DEFAULTS.minimum_success_rate,
101	      minimum_sample_size: (agentDefaults?.minimum_sample_size as number)
102	        ?? GLOBAL_DEFAULTS.minimum_sample_size,
103	      fallback_behavior: normalizeFallback(agentDefaults?.fallback_behavior)
104	        ?? GLOBAL_DEFAULTS.fallback_behavior,
105	    };
106	
107	    // Parse per-task overrides
108	    const thresholds = new Map<string, TaskConfidenceThreshold>();
109	    if (ctConfig) {
110	      for (const [taskType, raw] of Object.entries(ctConfig)) {
111	        if (taskType === '*') continue;
112	        thresholds.set(taskType, {
113	          minimum_success_rate: (raw.minimum_success_rate as number) ?? defaults.minimum_success_rate,
114	          minimum_sample_size: (raw.minimum_sample_size as number) ?? defaults.minimum_sample_size,
115	          fallback_behavior: normalizeFallback(raw.fallback_behavior) ?? defaults.fallback_behavior,
116	        });
117	      }
118	    }
119	
120	    const config: AgentConfidenceConfig = { thresholds, defaults };
121	
122	    configCache.set(key, { config, expiresAt: Date.now() + CONFIG_TTL_MS });
123	    return config;
124	  } catch {
125	    return { thresholds: new Map(), defaults: { ...GLOBAL_DEFAULTS } };
126	  }
127	}
128	
129	/**
130	 * Get the effective threshold for a specific task_type.
131	 * Merges: per-task override > agent default > global default.
132	 */
133	export async function getEffectiveThreshold(
134	  customerId: string,
135	  agentId: string,
136	  taskType: string,
137	): Promise<TaskConfidenceThreshold> {
138	  const config = await getConfidenceConfig(customerId, agentId);
139	  return config.thresholds.get(taskType) ?? config.defaults;
140	}
141	
142	/**
143	 * Check if an action passes confidence thresholds.
144	 * Returns { passed, behavior, reason? }.
145	 */
146	export function checkThreshold(
147	  threshold: TaskConfidenceThreshold,
148	  successRate: number,
149	  sampleSize: number,
150	): { passed: boolean; behavior: FallbackBehavior; reason?: string } {
151	  if (sampleSize < threshold.minimum_sample_size) {
152	    return {
153	      passed: false,
154	      behavior: threshold.fallback_behavior,
155	      reason: `Sample size ${sampleSize} < minimum ${threshold.minimum_sample_size}`,
156	    };
157	  }
158	
159	  if (successRate < threshold.minimum_success_rate) {
160	    return {
161	      passed: false,
162	      behavior: threshold.fallback_behavior,
163	      reason: `Success rate ${(successRate * 100).toFixed(0)}% < minimum ${(threshold.minimum_success_rate * 100).toFixed(0)}%`,
164	    };
165	  }
166	
167	  return { passed: true, behavior: 'allow' };
168	}
169	
170	/**
171	 * Apply thresholds to a list of scored actions.
172	 *
173	 * Returns the filtered/enriched list based on fallback behaviors:
174	 *   - "allow": no filtering
175	 *   - "warn": actions below threshold get a warning annotation
176	 *   - "omit": actions below threshold are removed
177	 */
178	export function applyThresholds(
179	  actions: Array<{
180	    action_id: string;
181	    action_name: string;
182	    composite_score: number;
183	    total_attempts: number;
184	    [key: string]: unknown;
185	  }>,
186	  threshold: TaskConfidenceThreshold,
187	): Array<{
188	  action_id: string;
189	  action_name: string;
190	  composite_score: number;
191	  total_attempts: number;
192	  threshold_warning?: string;
193	  [key: string]: unknown;
194	}> {
195	  if (threshold.fallback_behavior === 'allow') {
196	    return actions;
197	  }
198	
199	  return actions
200	    .map((action) => {
201	      const result = checkThreshold(
202	        threshold,
203	        action.composite_score,
204	        action.total_attempts,
205	      );
206	
207	      if (result.passed) return action;
208	
209	      if (threshold.fallback_behavior === 'omit') {
210	        return null; // filtered out below
211	      }
212	
213	      if (threshold.fallback_behavior === 'warn') {
214	        return {
215	          ...action,
216	          composite_score: Math.round(action.composite_score * 10000) / 10000,
217	          threshold_warning: result.reason,
218	        };
219	      }
220	
221	      return action;
222	    })
223	    .filter((a): a is NonNullable<typeof a> => a !== null);
224	}
225	
226	/** Invalidate cached config for an agent. */
227	export function invalidateThresholdConfig(customerId: string, agentId: string): void {
228	  configCache.delete(cacheKey(customerId, agentId));
229	}
230	
231	// ── Helpers ────────────────────────────────────────────────────
232	
233	function normalizeFallback(v: unknown): FallbackBehavior | null {
234	  if (typeof v !== 'string') return null;
235	  const lower = v.toLowerCase();
236	  if (lower === 'omit' || lower === 'warn' || lower === 'allow') {
237	    return lower;
238	  }
239	  return null;
240	}
