750	async function detectSilentFailure(
751	    sb: SupabaseClient,
752	    outcome: {
753	        outcome_id: string;
754	        customer_id: string;
755	        agent_id: string;
756	        action_id: string;
757	        action_name: string;
758	        success: boolean;
759	        outcome_score: number | null;
760	        business_outcome: string | null;
761	        error_code: string | null;
762	    }
763	): Promise<void> {
764	    const isSilentFailure =
765	        outcome.success === true && (
766	            // Explicit score signal: low score despite success flag
767	            (outcome.outcome_score !== null && outcome.outcome_score < 0.3) ||
768	            // Implicit signal: business outcome contradicts success flag
769	            (outcome.business_outcome === 'partial' || outcome.business_outcome === 'failed') ||
770	            // Implicit signal: error code present despite success=true
771	            (outcome.error_code != null && outcome.error_code.trim() !== '')
772	        );
773	
774	    if (!isSilentFailure) return;
775	
776	    const since24h = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
777	    const { data: recentAlert } = await sb
778	        .from('degradation_alert_events')
779	        .select('alert_id')
780	        .eq('customer_id', outcome.customer_id)
781	        .eq('action_id', outcome.action_id)
782	        .eq('alert_type', 'degradation')
783	        .gte('detected_at', since24h)
784	        .limit(1);
785	
786	    if (recentAlert && recentAlert.length > 0) return;
787	
788	    await sb.from('degradation_alert_events').insert({
789	        customer_id: outcome.customer_id,
790	        action_id: outcome.action_id,
791	        alert_type: 'degradation',
792	        severity: 'warning',
793	        current_value: outcome.outcome_score,
794	        baseline_value: 1.0,
795	        message: `Silent failure detected on "${outcome.action_name}": success=true but outcome_score=${outcome.outcome_score}. Technical success, business failure. Score will reflect true outcome.`,
796	    });
797	}

