368	export async function resolveActionIdForIngest(
369	    actionName: string,
370	    customerId: string,
371	): Promise<{ actionId: string; resolvedActionName: string }> {
372	    const { normalizeActionName } = await import('../middleware/validate-action.js');
373	    const normalized = normalizeActionName(actionName);
374	
375	    const rawLower = actionName
376	        .trim()
377	        .toLowerCase()
378	        .replace(/[-\s]+/g, '_')
379	        .replace(/_+/g, '_')
380	        .replace(/^_+|_+$/g, '');
381	
382	    if (rawLower && rawLower !== normalized) {
383	        const mergeReason = rawLower.match(/_v\d|_(final|new|old|temp|test|prod|dev|handler|fn|func|impl)$/)
384	            ? 'version_strip'
385	            : 'camel_normalize';
386	        void (async () => {
387	            try {
388	                const { error } = await supabase
389	                    .from('dim_action_aliases')
390	                    .upsert({
391	                        raw_name: rawLower,
392	                        canonical_name: normalized,
393	                        customer_id: customerId,
394	                        merge_reason: mergeReason,
395	                        merge_confidence: 1.0,
396	                        similarity: null,
397	                    }, {
398	                        onConflict: 'raw_name,customer_id',
399	                        ignoreDuplicates: true,
400	                    });
401	
402	                if (error && error.code !== '23505') {
403	                    console.warn('[ingest-core] alias upsert failed:', error.message);
404	                }
405	            } catch (err: unknown) {
406	                console.warn('[ingest-core] alias upsert threw:', (err as Error).message);
407	            }
408	        })();
409	    }
410	
411	    // Import payloads frequently contain historical/novel action names.
412	    // Resolve existing action first, then auto-register on first use.
413	    const { data: existing, error: lookupError } = await supabase
414	        .from('dim_actions')
415	        .select('action_id, action_name, is_active')
416	        .eq('action_name', normalized)
417	        .eq('customer_id', customerId)
418	        .maybeSingle();
419	
420	    if (lookupError) {
421	        throw new Error(`ACTION_LOOKUP_ERROR:${lookupError.message}`);
422	    }
423	
424	    if (existing) {
425	        if (!existing.is_active) {
426	            throw new Error(`ACTION_DISABLED:Action "${normalized}" is currently disabled`);
427	        }
428	        return { actionId: existing.action_id, resolvedActionName: existing.action_name };
429	    }
430	
431	    const { data: registered, error: registerError } = await supabase
432	        .from('dim_actions')
433	        .upsert(
434	            {
435	                action_name: normalized,
436	                customer_id: customerId,
437	                is_active: true,
438	                action_category: 'auto-discovered',
439	                action_description: 'Auto-registered on first use by historical import',
440	                required_params: {},
441	                validation_mode: 'advisory',
442	            },
443	            {
444	                onConflict: 'action_name,customer_id',
445	                ignoreDuplicates: false,
446	            }
447	        )
448	        .select('action_id, action_name, is_active')
449	        .maybeSingle();
450	
451	    if (registerError || !registered) {
452	        throw new Error(`ACTION_REGISTER_ERROR:${registerError?.message ?? 'No action row returned'}`);
453	    }
454	
455	    if (!registered.is_active) {
456	        throw new Error(`ACTION_DISABLED:Action "${normalized}" is currently disabled`);
457	    }
458	
459	    return { actionId: registered.action_id, resolvedActionName: registered.action_name };
460	}
