78	// ── Types ─────────────────────────────────────────────────────
79	
80	export interface InferenceSignals {
81	    // Layer 1 — always available
82	    success: boolean;
83	    retryAttempt: number | null;
84	    responseMs: number | null;
85	    errorCode: string | null;
86	    errorMessage: string | null;
87	
88	    // Layer 2 — optional soft signals
89	    businessOutcome: string | null;       // 'resolved'|'partial'|'failed'|'unknown'
90	    feedbackSignal: string | null;        // 'immediate'|'delayed'|'none'
91	    crossEventStatus: string | null;      // 'confirmed'|'conflict'|'resolved'|'pending_signal'
92	    verifierSource: string | null;        // from verifier.ts
93	    verifierValue: string | number | boolean | null;
94	
95	    // Layer 3 — adaptive baseline (fetched async before inference)
96	    actionBaseline: ActionBaseline | null;
97	}
98	
99	export interface ActionBaseline {
100	    p50ResponseMs: number;     // median of last 20 outcomes for this (agent, action)
101	    p75ResponseMs: number;     // 75th percentile
102	    recentSuccessRate: number; // success rate of last 20 outcomes
103	    sampleCount: number;       // how many outcomes exist — drives confidence
104	}
105	
106	export type OutcomeClass =
107	    | 'success'          // clean success, no issues
108	    | 'partial_success'  // succeeded but with friction (retries, slow, partial)
109	    | 'degraded'         // succeeded technically but signals suggest quality loss
110	    | 'failure'          // clean failure
111	    | 'uncertain';       // contradictory signals, cannot classify reliably
112	
113	export interface InferredOutcomeScore {
114	    score: number;           // 0.0–1.0
115	    confidence: number;      // 0.0–1.0 — how reliable this inference is
116	    class: OutcomeClass;
117	    origin: 'provided' | 'inferred';
118	    signalCount: number;     // how many signals contributed
119	    inferenceNotes: string[]; // human-readable list of what drove the score
120	}
121	
122	// ── Layer 1 — Hard Signals ────────────────────────────────────
123	// Objective, always-present signals. success is the minimum.
124	// error_code and retry_attempt add granularity to failure/success.
125	
126	function layer1Score(signals: InferenceSignals): {
127	    base: number;
128	    signalCount: number;
129	    notes: string[];
130	} {
131	    const notes: string[] = [];
132	    let signalCount = 1; // success is always present
133	
134	    if (!signals.success) {
135	        // Failure path — classify severity from error_code
136	        const code = (signals.errorCode ?? '').toLowerCase();
137	        const msg = (signals.errorMessage ?? '').toLowerCase();
138	
139	        if (code.includes('timeout') || msg.includes('timeout')) {
140	            notes.push('timeout_error: score=0.10');
141	            return { base: 0.10, signalCount, notes };
142	        }
143	        if (code.includes('partial') || msg.includes('partial')) {
144	            notes.push('partial_failure: score=0.25');
145	            return { base: 0.25, signalCount, notes };
146	        }
147	        if (code.includes('rate_limit') || code.includes('throttl')) {
148	            notes.push('rate_limit: score=0.15');
149	            return { base: 0.15, signalCount, notes };
150	        }
151	        notes.push('hard_failure: score=0.00');
152	        return { base: 0.00, signalCount, notes };
153	    }
154	
155	    // Success path
156	    let base = 1.0;
157	
158	    // Retry penalty — succeeded but took multiple attempts
159	    if (signals.retryAttempt !== null && signals.retryAttempt > 0) {
160	        signalCount++;
161	        const penalty = Math.min(0.30, signals.retryAttempt * 0.10);
162	        base -= penalty;
163	        notes.push(`retry_attempt=${signals.retryAttempt}: penalty=-${penalty.toFixed(2)}`);
164	    }
165	
166	    return { base, signalCount, notes };
167	}
168	
169	// ── Layer 2 — Soft Signals ────────────────────────────────────
170	// Optional high-value signals: business_outcome, cross_event, verifier.
171	// These can OVERRIDE Layer 1 when they carry stronger signal.
172	
173	function layer2Adjustment(signals: InferenceSignals, base: number): {
174	    adjusted: number;
175	    class: OutcomeClass;
176	    signalDelta: number;
177	    notes: string[];
178	} {
179	    const notes: string[] = [];
180	    let adjusted = base;
181	    let signalDelta = 0;
182	    let outcomeClass: OutcomeClass = signals.success ? 'success' : 'failure';
183	
184	    // business_outcome is the highest-value soft signal
185	    if (signals.businessOutcome) {
186	        signalDelta++;
187	        switch (signals.businessOutcome) {
188	            case 'resolved':
189	                adjusted = Math.max(adjusted, 0.85);
190	                outcomeClass = 'success';
191	                notes.push('business_outcome=resolved: floor=0.85');
192	                break;
193	            case 'partial':
194	                adjusted = Math.min(adjusted, 0.60);
195	                outcomeClass = 'partial_success';
196	                notes.push('business_outcome=partial: ceiling=0.60');
197	                break;
198	            case 'failed':
199	                adjusted = Math.min(adjusted, 0.15);
200	                outcomeClass = 'failure';
201	                notes.push('business_outcome=failed: ceiling=0.15');
202	                break;
203	            case 'unknown':
204	                // no adjustment — unknown is truly unknown
205	                break;
206	        }
207	    }
208	
209	    // cross_event_status — downstream confirmation
210	    if (signals.crossEventStatus) {
211	        signalDelta++;
212	        if (signals.crossEventStatus === 'confirmed') {
213	            adjusted = Math.max(adjusted, 0.80);
214	            notes.push('cross_event=confirmed: floor=0.80');
215	        } else if (signals.crossEventStatus === 'conflict') {
216	            adjusted = Math.min(adjusted, 0.40);
217	            outcomeClass = 'uncertain';
218	            notes.push('cross_event=conflict: ceiling=0.40, class=uncertain');
219	        } else if (signals.crossEventStatus === 'resolved') {
220	            adjusted = Math.max(adjusted, 0.75);
221	            notes.push('cross_event=resolved: floor=0.75');
222	        }
223	    }
224	
225	    // feedback_signal
226	    if (signals.feedbackSignal === 'delayed') {
227	        // Delayed feedback = deferred confirmation — slight uncertainty
228	        adjusted *= 0.95;
229	        signalDelta++;
230	        notes.push('feedback=delayed: confidence_factor=0.95');
231	    }
232	
233	    // verifier contradiction — success=true but verifier says false
234	    // (verifier.ts already flips verified_success, but we also reflect in score)
235	    if (signals.verifierSource && signals.verifierSource !== 'none' && signals.verifierValue === false) {
236	        adjusted = Math.min(adjusted, 0.10);
237	        outcomeClass = 'failure';
238	        signalDelta++;
239	        notes.push(`verifier=${signals.verifierSource} returned false: ceiling=0.10`);
240	    }
241	
242	    // Contradiction detection — success=true but got here with low base after retries + partial
243	    if (signals.success && adjusted < 0.50) {
244	        outcomeClass = 'degraded';
245	        notes.push('degraded: success=true but score<0.50 after adjustments');
246	    }
247	
248	    return { adjusted, class: outcomeClass, signalDelta, notes };
249	}
250	
251	// ── Layer 3 — Relative Performance ────────────────────────────
252	// Adaptive baseline: compare this outcome's latency against the
253	// action's own historical p50/p75 — NOT a hardcoded threshold.
254	// Only active when sufficient history exists (sampleCount >= 5).
255	
256	function layer3RelativeAdjustment(
257	    adjusted: number,
258	    signals: InferenceSignals,
259	): {
260	    final: number;
261	    confidenceDelta: number;
262	    notes: string[];
263	} {
264	    const notes: string[] = [];
265	    let confidenceDelta = 0;
266	    const baseline = signals.actionBaseline;
267	
268	    if (!baseline || baseline.sampleCount < 5) {
269	        // Not enough history — skip relative adjustment, but note it
270	        notes.push(`no_baseline: sampleCount=${baseline?.sampleCount ?? 0}`);
271	        return { final: adjusted, confidenceDelta: 0, notes };
272	    }
273	
274	    let final = adjusted;
275	
276	    // Latency relative to this action's own p75 baseline
277	    // Not hardcoded 5000ms — adaptive per action
278	    if (signals.responseMs !== null && baseline.p75ResponseMs > 0) {
279	        const ratio = signals.responseMs / baseline.p75ResponseMs;
280	        if (ratio > 3.0) {
281	            const penalty = Math.min(0.20, (ratio - 3.0) * 0.04);
282	            final -= penalty;
283	            confidenceDelta += 0.05; // more signals = more confidence in inference
284	            notes.push(`latency=${signals.responseMs}ms vs p75=${baseline.p75ResponseMs}ms (${ratio.toFixed(1)}x): penalty=-${penalty.toFixed(2)}`);
285	        } else if (ratio < 0.5) {
286	            // Faster than usual — slight positive signal
287	            final = Math.min(1.0, final + 0.05);
288	            notes.push(`latency=${signals.responseMs}ms is faster than p75 baseline: +0.05`);
289	        }
290	        confidenceDelta += 0.05;
291	    }
292	
293	    return { final: Math.max(0, Math.min(1, final)), confidenceDelta, notes };
294	}
295	
296	// ── Confidence Calculation ────────────────────────────────────
297	// Adaptive to signal count and historical sample depth.
298	// More signals + more history = higher confidence.
299	// Capped at 0.85 — inference is never as reliable as developer-provided.
300	
301	function computeInferenceConfidence(
302	    signalCount: number,
303	    sampleCount: number,
304	    hasContradiction: boolean,
305	): number {
306	    // Base: more signals = more confident
307	    // 1 signal (just success) → 0.42
308	    // 2 signals               → 0.54
309	    // 3 signals               → 0.66
310	    // 4+ signals              → 0.75 (capped)
311	    const base = Math.min(0.75, 0.30 + signalCount * 0.12);
312	
313	    // History boost: more historical samples = more reliable baseline
314	    const historyBoost = sampleCount >= 20 ? 0.10
315	        : sampleCount >= 10 ? 0.06
316	            : sampleCount >= 5 ? 0.03
317	                : 0;
318	
319	    // Contradiction penalty
320	    const contradictionPenalty = hasContradiction ? 0.20 : 0;
321	
322	    return Math.max(0.10, Math.min(0.85, base + historyBoost - contradictionPenalty));
323	}
324	
325	// ── Baseline Fetch ────────────────────────────────────────────
326	// Queries last 20 live SDK outcomes for this (agent, action) pair.
327	// Returns p50/p75 latency, success rate, and sample count.
328	// Returns null if insufficient data (< 5 outcomes).
329	
330	export async function fetchActionBaseline(
331	    agentId: string,
332	    actionId: string,
333	): Promise<ActionBaseline | null> {
334	    const cacheKey = baselineCacheKey(agentId, actionId);
335	    const now = Date.now();
336	    const cached = actionBaselineCache.get(cacheKey);
337	    if (cached && cached.expiresAt > now) {
338	        return cached.value;
339	    }
340	
341	    const { data } = await supabase
342	        .from('fact_outcomes')
343	        .select('response_time_ms, success')
344	        .eq('agent_id', agentId)
345	        .eq('action_id', actionId)
346	        .eq('ingestion_source', 'sdk')    // only live SDK signal; 'mcp' outcomes flow through the decision-tracker pipeline separately
347	        .eq('is_synthetic', false)
348	        .eq('is_deleted', false)          // exclude GDPR soft-deletes
349	        .order('timestamp', { ascending: false })
350	        .limit(20);
351	
352	    if (!data || data.length < 5) {
353	        actionBaselineCache.set(cacheKey, {
354	            value: null,
355	            expiresAt: now + getBaselineCacheTtlMs(),
356	        });
357	        return null;
358	    }
359	
360	    const latencies = data
361	        .map(r => r.response_time_ms)
362	        .filter((v): v is number => typeof v === 'number' && v > 0)
363	        .sort((a, b) => a - b);
364	
365	    if (latencies.length === 0) {
366	        actionBaselineCache.set(cacheKey, {
367	            value: null,
368	            expiresAt: now + getBaselineCacheTtlMs(),
369	        });
370	        return null;
371	    }
372	
373	    const p50 = latencies[Math.floor(latencies.length * 0.5)] ?? 0;
374	    const p75 = latencies[Math.floor(latencies.length * 0.75)] ?? p50;
375	    const successes = data.filter(r => r.success).length;
376	
377	    const baseline: ActionBaseline = {
378	        p50ResponseMs: p50,
379	        p75ResponseMs: p75,
380	        recentSuccessRate: successes / data.length,
381	        sampleCount: data.length,
382	    };
383	
384	    actionBaselineCache.set(cacheKey, {
385	        value: baseline,
386	        expiresAt: now + getBaselineCacheTtlMs(),
387	    });
388	
389	    if (actionBaselineCache.size > BASELINE_CACHE_MAX_ENTRIES) {
390	        const oldestKey = actionBaselineCache.keys().next().value as string | undefined;
391	        if (oldestKey) actionBaselineCache.delete(oldestKey);
392	    }
393	
394	    return baseline;
395	}
396	
397	// ── Public Entry Point ────────────────────────────────────────
398	// Runs all 3 layers sequentially and produces a final score.
399	// This is the ONLY export that callers need for inference.
400	// fetchActionBaseline must be called separately before this
401	// (async DB fetch cannot be inside a sync function).
402	
403	export function inferOutcomeScore(signals: InferenceSignals): InferredOutcomeScore {
404	    const l1 = layer1Score(signals);
405	    const l2 = layer2Adjustment(signals, l1.base);
406	    const l3 = layer3RelativeAdjustment(l2.adjusted, signals);
407	
408	    const totalSignalCount = l1.signalCount + l2.signalDelta;
409	    const hasContradiction = l2.class === 'uncertain';
410	
411	    const confidence = computeInferenceConfidence(
412	        totalSignalCount,
413	        signals.actionBaseline?.sampleCount ?? 0,
414	        hasContradiction,
415	    );
416	
417	    return {
418	        score: Number(l3.final.toFixed(4)),
419	        confidence: Number(confidence.toFixed(4)),
420	        class: l2.class,
421	        origin: 'inferred',
422	        signalCount: totalSignalCount,
423	        inferenceNotes: [...l1.notes, ...l2.notes, ...l3.notes],
424	    };
425	}
