201	function evaluateInconsistency(params: {
202	    finalSuccess: boolean;
203	    outcomeScoreRaw: number | null;
204	    businessOutcome: string | null | undefined;
205	    verifierDiscrepancy: boolean;
206	}): InconsistencyEvaluation {
207	    const lowThreshold = clamp01(
208	        parseOptionalNumber(process.env.LI_INCONSISTENCY_THRESHOLD) ?? 0.3,
209	    );
210	    const highThreshold = clamp01(
211	        parseOptionalNumber(process.env.LI_INCONSISTENCY_HIGH_THRESHOLD) ?? 0.7,
212	    );
213	
214	    if (params.verifierDiscrepancy) {
215	        return {
216	            isInconsistent: true,
217	            type: 'verifier_discrepancy',
218	            reason: 'Verifier signal contradicted self-reported outcome.',
219	            ruleVersion: 'v2:verifier_discrepancy',
220	        };
221	    }
222	
223	    if (
224	        params.finalSuccess === true
225	        && params.outcomeScoreRaw !== null
226	        && params.outcomeScoreRaw < lowThreshold
227	    ) {
228	        return {
229	            isInconsistent: true,
230	            type: 'success_low_score',
231	            reason: `success=true but outcome_score_raw=${params.outcomeScoreRaw.toFixed(4)} is below threshold ${lowThreshold.toFixed(4)}.`,
232	            ruleVersion: `v2:success_low_score:threshold=${lowThreshold.toFixed(4)}`,
233	        };
234	    }
235	
236	    if (
237	        params.finalSuccess === false
238	        && params.outcomeScoreRaw !== null
239	        && params.outcomeScoreRaw > highThreshold
240	    ) {
241	        return {
242	            isInconsistent: true,
243	            type: 'failure_high_score',
244	            reason: `success=false but outcome_score_raw=${params.outcomeScoreRaw.toFixed(4)} exceeds threshold ${highThreshold.toFixed(4)}.`,
245	            ruleVersion: `v2:failure_high_score:threshold=${highThreshold.toFixed(4)}`,
246	        };
247	    }
248	
249	    if (
250	        params.finalSuccess === true
251	        && (params.businessOutcome === 'partial' || params.businessOutcome === 'failed')
252	    ) {
253	        return {
254	            isInconsistent: true,
255	            type: 'success_business_conflict',
256	            reason: `success=true but business_outcome=${params.businessOutcome}.`,
257	            ruleVersion: 'v2:success_business_conflict',
258	        };
259	    }
260	
261	    return {
262	        isInconsistent: false,
263	        type: null,
264	        reason: null,
265	        ruleVersion: null,
266	    };
267	}
