301	                if (['true', '1', 'yes', 'ok', 'pass', 'resolved'].includes(lower)) return true;
302	                if (['false', '0', 'no', 'fail', 'failed'].includes(lower)) return false;
303	            }
304	            if (typeof val === 'number') return val === 1;
305	            return val;
306	        },
307	        z.boolean(),
308	    ),
309	    response_time_ms: z.preprocess(
310	        (val) => {
311	            if (typeof val === 'number') {
312	                return Number.isFinite(val) && val > 0 ? Math.round(val) : undefined;
313	            }
314	            if (typeof val === 'string') {
315	                const parsed = Number(val);
316	                return Number.isFinite(parsed) && parsed > 0 ? Math.round(parsed) : undefined;
317	            }
318	            return val;
319	        },
320	        z.number().int().positive().optional(),
321	    ),
322	    response_ms: z.preprocess(
323	        (val) => {
324	            if (typeof val === 'number') {
325	                return Number.isFinite(val) && val > 0 ? Math.round(val) : undefined;
326	            }
327	            if (typeof val === 'string') {
328	                const parsed = Number(val);
329	                return Number.isFinite(parsed) && parsed > 0 ? Math.round(parsed) : undefined;
330	            }
331	            return val;
332	        },
333	        z.number().int().positive().optional(),
334	    ), // SDK alias — maps to response_time_ms
