336	    error_message: z.string().max(1000).optional(),
337	    raw_context: z.record(z.string(), z.unknown()).optional(),
338	    // Any string is accepted. Common abbreviations are normalized.
339	    // Unknown values default to 'production'. Field is metadata-only —
340	    // not referenced by any conditional branch in scoring or policy.
341	    environment: z
342	        .string()
343	        .max(50)
344	        .optional()
345	        .default('production')
346	        .transform(val => {
347	            const normalized = val.trim().toLowerCase();
348	            const aliases: Record<string, string> = {
349	                'prod': 'production',
350	                'dev': 'development',
351	                'develop': 'development',
352	                'stage': 'staging',
353	                'stg': 'staging',
354	                'qa': 'staging',
355	                'test': 'staging',
356	                'uat': 'staging',
357	            };
358	            if (aliases[normalized]) return aliases[normalized] as 'production' | 'staging' | 'development';
359	            const known = ['production', 'staging', 'development'] as const;
