532	export async function parseAndSanitizeRequest(c: Context) {
533	    let body: z.infer<typeof LogOutcomeBody>;
534	    try {
535	        const raw = c.get('parsed_body') ?? await c.req.json();
536	        body = LogOutcomeBody.parse(raw);
537	    } catch (err: any) {
538	        // Surface field-level zod errors so callers know exactly what's missing
539	        const details = err.errors
540	            ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
541	            : err.message;
542	        throw new Error(`VALIDATION_ERROR:${details}`);
543	    }
544	
545	    // Auto-generate session_id when not provided.
546	    // SDK always sends one (UUID per call), so this fallback is for
547	    // edge cases only (e.g. direct API callers). No quality penalty applied —
548	    // the SDK guarantees session_id is always present.
549	    if (!body.session_id) {
550	        body.session_id = crypto.randomUUID();
551	    }
552	
553	    // Normalize response_ms (SDK alias) → response_time_ms
554	    (body as any).response_time_ms = body.response_time_ms ?? (body as any).response_ms ?? undefined;
555	
556	    if (body.raw_context) body.raw_context = sanitizeContext(body.raw_context);
557	    if (body.error_message) body.error_message = sanitizeString(body.error_message, 1000);
558	    if (body.error_code) body.error_code = sanitizeString(body.error_code, 100);
559	
560	    // Payload size check
561	    if (body.raw_context) {
562	        const contextSize = new TextEncoder().encode(JSON.stringify(body.raw_context)).length;
563	        if (contextSize > MAX_RAW_CONTEXT_BYTES) {
564	            throw new Error('PAYLOAD_TOO_LARGE');
565	        }
566	    }
567	    return body;
568	}
