218	                label: `${normalizedIssueType} / ${normalizedEnv}${customerTier ? ` / ${customerTier}` : ''}`,
219	            };
220	        }
221	
222	        // Fallback: match just issue_type for this customer (ignore environment)
223	        const { data: fuzzy } = await supabase
224	            .from('dim_contexts')
225	            .select('context_id, issue_type, environment')
226	            .eq('customer_id', customerId)
227	            .eq('issue_type', normalizedIssueType)
228	            .limit(1)
229	            .maybeSingle();
230	
231	        if (fuzzy?.context_id) {
232	            return {
233	                resolved: true,
234	                contextId: fuzzy.context_id as string,
235	                label: `${normalizedIssueType} / ${fuzzy.environment ?? 'any'} (env fallback)`,
236	            };
237	        }
238	
239	        // Context doesn't exist yet — cold start; signal is globally blended
240	        return { resolved: false, contextId: null, label: `${normalizedIssueType} (cold start)` };
241	    } catch {
242	        return { resolved: false, contextId: null, label: null };
243	    }
244	}
