274	async function getRecommendationWithTaskFallback(
275	    customerId: string,
276	    requestedTaskName: string,
277	    agentId: string | null,
278	    contextFilter?: ContextFilter | null,
279	): Promise<{ taskName: string; result: RecommendationResult }> {
280	    const primaryTaskName = requestedTaskName.trim();
281	    const normalizedTaskName = normalizeTaskSlug(primaryTaskName);
282	
283	    const primaryResult = await getRecommendation(customerId, primaryTaskName, agentId, contextFilter);
284	
285	    if (
286	        normalizedTaskName.length === 0
287	        || normalizedTaskName === primaryTaskName
288	        || hasRecommendationEvidence(primaryResult)
289	        || primaryResult.state !== 'no_data'
290	    ) {
291	        return { taskName: primaryTaskName, result: primaryResult };
292	    }
293	
294	    const normalizedResult = await getRecommendation(customerId, normalizedTaskName, agentId, contextFilter);
295	    if (hasRecommendationEvidence(normalizedResult) || normalizedResult.state !== 'no_data') {
296	        return { taskName: normalizedTaskName, result: normalizedResult };
297	    }
298	
299	    return { taskName: primaryTaskName, result: primaryResult };
