336	async function fetchAgentTaskOutcomeTotals(params: {
337	    customerId: string;
338	    agentId: string | null;
339	}): Promise<{
340	    agentTaskTotals: Map<string, Map<string, number>>;
341	    agentGrandTotals: Map<string, number>;
342	    agentSuccessStats: Map<string, { wins: number; rated: number }>;
343	    source: 'fact_outcomes';
344	}> {
345	    const { customerId, agentId } = params;
346	    const agentTaskTotals = new Map<string, Map<string, number>>();
347	    const agentGrandTotals = new Map<string, number>();
348	    const agentSuccessStats = new Map<string, { wins: number; rated: number }>();
349	
350	    for (let offset = 0; ; offset += SUPABASE_PAGE_SIZE) {
351	        let factsQuery = supabase
352	            .from('fact_outcomes')
353	            .select('agent_id, task_name, success, outcome_score, outcome_score_raw')
354	            .eq('customer_id', customerId)
355	            .eq('is_synthetic', false)
356	            .eq('is_deleted', false)
357	            .neq('agent_id', ZERO_UUID_AGENT_ID)
358	            .range(offset, offset + SUPABASE_PAGE_SIZE - 1);
359	
360	        if (agentId) {
361	            factsQuery = factsQuery.eq('agent_id', agentId);
362	        }
363	
364	        const { data, error } = await factsQuery;
365	        if (error) {
366	            throw new Error(`[agent-summary] fallback aggregation failed: ${error.message}`);
367	        }
368	
369	        const page = (data ?? []) as Array<{ 
370	            agent_id: string | null; 
371	            task_name: string | null;
372	            success: boolean | null;
373	            outcome_score: number | null;
374	            outcome_score_raw: number | null;
375	        }>;
376	        for (const row of page) {
377	            addOutcomeCount(
378	                agentTaskTotals,
379	                agentGrandTotals,
380	                agentSuccessStats,
381	                row.agent_id ?? '',
382	                row.task_name ?? '',
383	                1,
384	                row.success,
385	                row.outcome_score,
386	                row.outcome_score_raw
387	            );
388	        }
389	
390	        if (page.length < SUPABASE_PAGE_SIZE) {
391	            break;
392	        }
393	    }
394	
395	    return { agentTaskTotals, agentGrandTotals, agentSuccessStats, source: 'fact_outcomes' };
396	}
