79	function sourceSignalWeight(
80	    ingestionSource: unknown,
81	    timestamp: string | null,
82	    driftSlope = 0,
83	    dynamicImportFloor = IMPORT_SIGNAL_WEIGHT,
84	): number {
85	    if (ingestionSource !== 'import') return 1.0;
86	
87	    const boundedFloor = clampWeight(dynamicImportFloor, IMPORT_SIGNAL_WEIGHT);
88	    let blended = boundedFloor;
89	
90	    if (timestamp) {
91	        const ts = Date.parse(timestamp);
92	        if (Number.isFinite(ts)) {
93	            const ageDays = Math.max(0, (Date.now() - ts) / (24 * 60 * 60 * 1000));
94	            if (ageDays <= IMPORT_WARM_START_FRESH_DAYS) {
95	                blended = 1.0;
96	            } else if (ageDays >= IMPORT_WARM_START_HISTORICAL_DAYS) {
97	                blended = boundedFloor;
98	            } else {
99	                const ratio = (ageDays - IMPORT_WARM_START_FRESH_DAYS)
100	                    / (IMPORT_WARM_START_HISTORICAL_DAYS - IMPORT_WARM_START_FRESH_DAYS);
101	                blended = 1.0 - (ratio * (1.0 - boundedFloor));
102	            }
103	        }
104	    }
105	
106	    if (Number.isFinite(driftSlope) && driftSlope < IMPORT_DRIFT_PENALTY_THRESHOLD) {
107	        const slopeDelta = Math.abs(driftSlope - IMPORT_DRIFT_PENALTY_THRESHOLD);
108	        const penalty = Math.max(
109	            IMPORT_DRIFT_PENALTY_MIN_WEIGHT,
110	            Math.min(1.0, Math.exp(-slopeDelta * IMPORT_DRIFT_PENALTY_STRENGTH)),
111	        );
112	        blended *= penalty;
113	    }
114	
115	    return Math.max(IMPORT_SOURCE_MIN_WEIGHT, Math.min(1.0, blended));
116	}
