118	function reliabilitySignalWeight(params: {
119	    isInconsistent: unknown;
120	    outcomeClass: unknown;
121	}): number {
122	    let weight = 1.0;
123	
124	    if (params.isInconsistent === true) {
125	        weight *= INCONSISTENT_SIGNAL_WEIGHT;
126	    }
127	
128	    const outcomeClass = typeof params.outcomeClass === 'string'
129	        ? params.outcomeClass
130	        : null;
131	
132	    if (outcomeClass === 'uncertain') {
133	        weight *= UNCERTAIN_CLASS_SIGNAL_WEIGHT;
134	    } else if (outcomeClass === 'degraded') {
135	        weight *= DEGRADED_CLASS_SIGNAL_WEIGHT;
136	    }
137	
138	    return Math.max(0, Math.min(1, weight));
139	}
