293	function computeDynamicImportFloor(successCount: number, totalCount: number): number {
294	    if (totalCount <= 0) return IMPORT_SIGNAL_WEIGHT;
295	    const successRate = clamp01(successCount / totalCount);
296	    const variance = successRate * (1 - successRate);
297	    const dynamicFloor = 0.5 - (variance * 1.6);
298	    return Math.max(0.1, Math.min(0.5, dynamicFloor));
