304	    const denominator = Math.log10(1 + IMPORT_SAMPLE_CONFIDENCE_IDEAL_SAMPLES);
305	    if (!Number.isFinite(numerator) || !Number.isFinite(denominator) || denominator <= 0) {
306	        return 0.1;
307	    }
308	    const confidence = numerator / denominator;
309	    return Math.max(0.1, Math.min(1, confidence));
