312	function computeActionDriftSlope(signalRows: ResolutionSignalRow[]): number {
313	    const chronologicalScores = signalRows
314	        .filter((row) => row.ingestionSource !== 'import')
315	        .map((row) => ({
316	            score: row.score,
317	            time: parseIso(row.timestamp),
318	            sequence: row.sequence,
319	        }));
320	
321	    if (chronologicalScores.length < IMPORT_DRIFT_MIN_SAMPLES) {
322	        return 0;
323	    }
324	
325	    chronologicalScores.sort((a, b) => {
326	        if (a.time === b.time) return a.sequence - b.sequence;
327	        return a.time - b.time;
328	    });
329	
330	    const regression = linearRegression(chronologicalScores.map((point) => point.score));
331	    return Number.isFinite(regression.slope) ? regression.slope : 0;
332	}
