517	            success_count: 0,
518	            score_sum: 0,
519	            weighted_score_sum: 0,
520	            weight_total: 0,
521	            cluster_counts: new Map<string, number>(),
522	            cluster_samples: 0,
523	            cluster_confidence_sum: 0,
524	            cluster_confidence_count: 0,
525	            signal_rows: [],
526	        };
527	        current.total += 1;
528	        if (derivedSuccess) {
529	            current.success_count += 1;
530	        }
531	        current.score_sum += score;
532	
533	        current.signal_rows.push({
534	            score,
535	            timestamp,
536	            ingestionSource: row.ingestion_source,
537	            qualityMultiplier,
538	            reliabilityMultiplier,
539	            sequence: sequence++,
