563	            const recencyWeight = computeOutcomeEffectiveWeightForScore(
564	                signalRow.score,
565	                signalRow.timestamp,
566	            );
567	            const sourceMultiplier = sourceSignalWeight(
568	                signalRow.ingestionSource,
569	                signalRow.timestamp,
570	                driftSlope,
571	                dynamicImportFloor,
572	            );
573	            const effectiveWeight = recencyWeight
574	                * signalRow.qualityMultiplier
575	                * sourceMultiplier
576	                * signalRow.reliabilityMultiplier
577	                * sampleConfidence;
578	            if (effectiveWeight > 0) {
579	                bucket.weight_total += effectiveWeight;
580	                bucket.weighted_score_sum += signalRow.score * effectiveWeight;
581	            }
582	        }
583	    }
584	
585	    return grouped;
586	}
