642	async function getTaskResolutionStatsByAction(
643	    params: FetchTaskPerformanceParams,
644	): Promise<Map<string, TaskResolutionStats>> {
645	    const contextId = params.contextFilter?.resolved
646	        ? (params.contextFilter.contextId ?? null)
647	        : null;
648	
649	    // Always fetch global stats — used as fallback / blend base
650	    const globalData = await queryResolutionRows(params, null);
651	    if (globalData.length === 0) {
652	        return new Map<string, TaskResolutionStats>();
653	    }
654	
655	    const globalGrouped = aggregateResolutionRows(globalData);
656	    const globalStats = groupedToStats(globalGrouped);
657	
658	    // No context filter — return global stats directly
659	    if (!contextId) {
660	        const out = new Map<string, TaskResolutionStats>();
661	        for (const [actionId, s] of globalStats.entries()) {
662	            out.set(actionId, {
663	                resolutionRate: s.resolutionRate,
664	                effectiveSamples: s.effectiveSamples,
665	                semanticClusterConvergence: s.semanticClusterConvergence,
666	            });
667	        }
668	        return out;
669	    }
670	
671	    // Fetch context-specific stats
672	    const contextData = await queryResolutionRows(params, contextId);
673	    const contextGrouped = aggregateResolutionRows(contextData);
674	    const contextStats = groupedToStats(contextGrouped);
675	
676	    // Blend: interpolate between context-specific and global using sample-weighted alpha.
677	    // When context has >= CONTEXT_MIN_SAMPLES_FULL_TRUST outcomes → full context trust (alpha=1).
678	    // When context has 0 outcomes → full global trust (alpha=0).
679	    // Linear ramp between 0 and CONTEXT_MIN_SAMPLES_FULL_TRUST.
680	    const out = new Map<string, TaskResolutionStats>();
681	    for (const [actionId, global] of globalStats.entries()) {
682	        const ctx = contextStats.get(actionId);
683	        if (!ctx || ctx.effectiveSampleCount <= 0) {
684	            // No context-specific data for this action — use global
685	            out.set(actionId, {
686	                resolutionRate: global.resolutionRate,
687	                effectiveSamples: global.effectiveSamples,
688	                semanticClusterConvergence: global.semanticClusterConvergence,
689	            });
690	            continue;
691	        }
692	
693	        // Sample-weighted blend: alpha ramps from 0→1 as context samples grow
694	        const alpha = Math.min(1, ctx.effectiveSampleCount / CONTEXT_MIN_SAMPLES_FULL_TRUST);
695	        const blendedRate = clamp01(alpha * ctx.resolutionRate + (1 - alpha) * global.resolutionRate);
696	        // Effective samples = context-specific weighted count (what the engine will use for confidence)
697	        const blendedSamples = alpha * ctx.effectiveSamples + (1 - alpha) * global.effectiveSamples;
698	        // Cluster convergence: prefer context-specific if mature, else global
699	        const blendedConvergence = alpha * ctx.semanticClusterConvergence + (1 - alpha) * global.semanticClusterConvergence;
700	
701	        out.set(actionId, {
702	            resolutionRate: Number(blendedRate.toFixed(4)),
703	            effectiveSamples: Number(blendedSamples.toFixed(4)),
704	            semanticClusterConvergence: Number(blendedConvergence.toFixed(4)),
705	        });
706	    }
707	
708	    return out;
709	}
