711	async function queryTaskPerformanceFromFacts(
712	    params: FetchTaskPerformanceParams,
713	): Promise<TaskPerformanceRow[]> {
714	    let query = supabase
715	        .from('fact_outcomes')
716	        .select('action_id, success, execution_status, outcome_score, outcome_score_raw, data_quality, ingestion_source, is_inconsistent, outcome_class, timestamp, semantic_cluster_key, semantic_cluster_confidence, dim_actions!inner(action_name)')
717	        .eq('customer_id', params.customerId)
718	        .eq('is_deleted', false)
719	        .eq('is_synthetic', false)
720	        .eq('task_name', params.taskName);
721	
722	    if (params.windowStart) {
723	        query = query.gte('timestamp', params.windowStart);
724	    }
725	
726	    if (params.agentId) {
727	        query = query.eq('agent_id', params.agentId);
728	    } else {
729	        query = query.neq('agent_id', ZERO_UUID_AGENT_ID);
730	    }
731	
732	    const { data, error } = await query;
733	
734	    if (error) {
735	        throw new Error(`[task-performance] fallback query failed: ${error.message}`);
736	    }
737	
738	    const grouped = new Map<string, {
739	        action_id: string;
740	        action_name: string;
741	        total_count: number;
742	        success_count: number;
743	        last_seen_at: string | null;
744	    }>();
745	
746	    const factRows = (data ?? []) as Array<Record<string, unknown>>;
747	
748	    for (const row of factRows) {
749	        const actionId = typeof row.action_id === 'string' ? row.action_id : null;
750	        if (!actionId) continue;
751	
752	        const dimActions = row.dim_actions;
753	        let actionName = actionId;
754	
755	        if (isObject(dimActions) && typeof dimActions.action_name === 'string') {
756	            actionName = dimActions.action_name;
757	        } else if (Array.isArray(dimActions) && dimActions.length > 0) {
758	            const first = dimActions[0];
759	            if (isObject(first) && typeof first.action_name === 'string') {
760	                actionName = first.action_name;
761	            }
762	        }
763	
764	        // Key by action_id only — action_name can vary across dim_actions rows
765	        // due to normalization lag. Using a composite key would create duplicate
766	        // entries for the same action appearing under slightly different names.
767	        const key = actionId;
768	        const existing = grouped.get(key) ?? {
769	            action_id: actionId,
770	            action_name: actionName,
771	            total_count: 0,
772	            success_count: 0,
773	            last_seen_at: null,
774	        };
775	
776	        existing.total_count += 1;
777	        if (row.success === true) {
778	            existing.success_count += 1;
779	        }
780	
781	        const ts = typeof row.timestamp === 'string' ? row.timestamp : null;
782	
783	        existing.last_seen_at = latestTimestamp(existing.last_seen_at, ts);
784	
785	        grouped.set(key, existing);
786	    }
787	
788	    const resolutionStatsByAction = groupedToStats(aggregateResolutionRows(factRows));
789	
790	    const actionIds = Array.from(
791	        new Set(Array.from(grouped.values()).map((row) => row.action_id)),
792	    );
793	    const mlScoreByAction = await getLatestMlScoreByAction(params.customerId, actionIds);
794	
795	    return Array.from(grouped.values()).map((row) => {
796	        const successRate = row.total_count > 0
797	            ? Number((row.success_count / row.total_count).toFixed(4))
798	            : 0;
799	        const resolutionStats = resolutionStatsByAction.get(row.action_id);
800	        const resolutionRate = row.total_count > 0
801	            ? Number((
802	                resolutionStats?.resolutionRate
803	                ?? successRate
804	            ).toFixed(4))
805	            : successRate;
806	
807	        return {
808	            action_id: row.action_id,
809	            action_name: row.action_name,
810	            total_count: row.total_count,
811	            effective_sample_count: Number((
812	                resolutionStats?.effectiveSamples
813	                ?? row.total_count
814	            ).toFixed(4)),
815	            success_count: row.success_count,
816	            success_rate: successRate,
817	            resolution_rate: resolutionRate,
818	            semantic_cluster_convergence: resolutionStats?.semanticClusterConvergence ?? 0.5,
819	            ml_score: mlScoreByAction.get(row.action_id) ?? null,
820	            last_seen_at: row.last_seen_at,
821	        };
822	    });
823	}
