842	export async function fetchAvailableTasks(
843	    customerId: string,
844	    scopedAgentId: string | null,
845	): Promise<{ tasks: string[]; source: 'mv' | 'fact_fallback' }> {
846	    const mvRows: Array<{ task_name: unknown }> = [];
847	    let mvError: QueryError | null = null;
848	
849	    for (let offset = 0; ; offset += SUPABASE_PAGE_SIZE) {
850	        let mvQuery = supabase
851	            .from(TASK_PERFORMANCE_MV)
852	            .select('task_name')
853	            .eq('customer_id', customerId)
854	            .neq('agent_id', ZERO_UUID_AGENT_ID);
855	
856	        mvQuery = applySupabasePagination(mvQuery, offset);
857	
858	        if (scopedAgentId) {
859	            mvQuery = mvQuery.eq('agent_id', scopedAgentId);
860	        }
861	
862	        const { data, error } = await mvQuery;
863	        if (error) {
864	            mvError = error as QueryError;
865	            break;
866	        }
867	
868	        const page = (data ?? []) as Array<{ task_name: unknown }>;
869	        mvRows.push(...page);
870	        if (page.length < SUPABASE_PAGE_SIZE) {
871	            break;
872	        }
873	    }
874	
875	    if (!mvError) {
876	        const tasks = [
877	            ...new Set(mvRows
878	                .map((row: any) => normalizeTaskName(row.task_name))
879	                .filter((task): task is string => task !== null)),
880	        ].sort();
881	
882	        return { tasks, source: 'mv' };
883	    }
884	
885	    const reason = isMissingMvError(mvError)
886	        ? 'materialized view is missing'
887	        : mvError.message;
888	    console.warn('[task-performance] task list fallback activated:', reason);
889	
890	    const fallbackRows: Array<{ task_name: unknown }> = [];
891	    const windowStart = new Date(
892	        Date.now() - RECOMMENDATION_WINDOW_DAYS * 24 * 60 * 60 * 1000,
893	    ).toISOString();
894	
895	    for (let offset = 0; ; offset += SUPABASE_PAGE_SIZE) {
896	        let fallbackQuery = supabase
897	            .from('fact_outcomes')
898	            .select('task_name')
899	            .eq('customer_id', customerId)
900	            .eq('is_deleted', false)
901	            .eq('is_synthetic', false)
902	            .not('task_name', 'is', null)
903	            .neq('agent_id', ZERO_UUID_AGENT_ID)
904	            .gte('timestamp', windowStart);
905	
906	        fallbackQuery = applySupabasePagination(fallbackQuery, offset);
907	
908	        if (scopedAgentId) {
909	            fallbackQuery = fallbackQuery.eq('agent_id', scopedAgentId);
910	        }
911	
912	        const { data, error } = await fallbackQuery;
913	
914	        if (error) {
915	            throw new Error(`[task-performance] task list fallback failed: ${error.message}`);
916	        }
917	
918	        const page = (data ?? []) as Array<{ task_name: unknown }>;
919	        fallbackRows.push(...page);
920	        if (page.length < SUPABASE_PAGE_SIZE) {
921	            break;
922	        }
923	    }
924	
925	    const tasks = [
926	        ...new Set(fallbackRows
927	            .map((row: any) => normalizeTaskName(row.task_name))
928	            .filter((task): task is string => task !== null)),
929	    ].sort();
930	
931	    return { tasks, source: 'fact_fallback' };
932	}
